let tts=null,ready=false;self.onmessage=async e=>{const{type,text,voice}=e.data;if(type==='init'){try{const{KokoroTTS}=await import('https://cdn.jsdelivr.net/npm/kokoro-js@1.1.0/+esm');tts=await KokoroTTS.from_pretrained('onnx-community/Kokoro-82M-v1.0-ONNX',{dtype:'q8',device:'wasm'});ready=true;self.postMessage({type:'ready'})}catch(e){self.postMessage({type:'error',message:e.message})}return}if(type==='generate'){if(!ready||!tts){self.postMessage({type:'error',message:'TTS not ready'});return}try{const r=await tts.generate(text,{voice});const a=new Float32Array(r.audio);self.postMessage({type:'audio',audio:a,samplingRate:r.sampling_rate},[a.buffer])}catch(e){self.postMessage({type:'error',message:e.message})}}};
